14	// Process items with at most `concurrency` in-flight at once.
15	// Prevents OOM when cap=500 spawns 24+ parallel Playwright tabs or fetch requests.
16	async function pooledMap<T, R>(
17	  items: T[],
18	  fn: (item: T) => Promise<R>,
19	  concurrency: number
20	): Promise<R[]> {
21	  const results: R[] = new Array(items.length);
22	  let next = 0;
23	  async function worker() {
24	    while (next < items.length) {
25	      const i = next++;
26	      results[i] = await fn(items[i]);
27	    }
28	  }
29	  await Promise.all(Array.from({ length: Math.min(concurrency, items.length) }, worker));
30	  return results;
31	}
