63	      author: r.consumer?.displayName?.trim() || undefined,
64	      rating: typeof r.rating === 'number' ? r.rating : null,
65	      date: r.createdAt
66	        ? new Date(r.createdAt).toISOString().split('T')[0]
67	        : new Date().toISOString().split('T')[0],
68	      text,
69	      verified: r.isVerified === true || r.labels?.verification?.isVerified === true,
70	      sourceReviewId: r.id || undefined,
71	      sourceUrl: r.id ? `https://www.trustpilot.com/reviews/${r.id}` : undefined,
72	    });
